144	  func moveCaret(forward: Bool) -> Bool {
145	    let currentCaretPos = rimeAPI.get_caret_pos(session)
146	    guard let input = rimeAPI.get_input(session) else { return false }
147	    if forward {
148	      if currentCaretPos <= 0 {
149	        return false
150	      }
151	      rimeAPI.set_caret_pos(session, currentCaretPos - 1)
152	    } else {
153	      let inputStr = String(cString: input)
154	      if currentCaretPos >= inputStr.utf8.count {
155	        return false
156	      }
157	      rimeAPI.set_caret_pos(session, currentCaretPos + 1)
158	    }
159	    rimeUpdate()
160	    return true
161	  }
